css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #030712; color: white; min-height: 100vh; }
.page { display: grid; grid-template-columns: 1fr 1fr; min-height: 100vh; }
.left { background: linear-gradient(160deg, #1e3a5f, #1d4ed8, #2563eb); padding: 80px 60px; display: flex; flex-direction: column; justify-content: center; }
.brand { font-size: 26px; font-weight: 900; margin-bottom: 56px; }
.left h1 { font-size: 60px; font-weight: 900; line-height: 1.05; letter-spacing: -2px; margin-bottom: 20px; }
.left p { color: rgba(255,255,255,0.7); font-size: 17px; line-height: 1.7; margin-bottom: 48px; }
.features { display: flex; flex-direction: column; gap: 20px; }
.feature { display: flex; align-items: center; gap: 16px; } .f-icon { font-size: 24px; width: 48px; height: 48px; background: rgba(255,255,255,0.15); border-radius: 12px; display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
.feature strong { display: block; font-size: 15px; font-weight: 700; } .feature small { color: rgba(255,255,255,0.6); font-size: 13px; }
.right { background: #0a0a0f; display: flex; align-items: center; justify-content: center; padding: 40px; overflow-y: auto; }
.form-card { width: 100%; max-width: 440px; }
.form-card h2 { font-size: 32px; font-weight: 800; margin-bottom: 6px; }
.sub { color: #6b7280; font-size: 14px; margin-bottom: 28px; } .sub a { color: #3b82f6; text-decoration: none; font-weight: 600; }
.form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; }
.form-group { margin-bottom: 16px; }
.form-group label { display: block; font-size: 14px; font-weight: 600; margin-bottom: 7px; color: #e2e8f0; }
.form-group input { width: 100%; height: 48px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.05); color: white; padding: 0 14px; font-size: 15px; outline: none; transition: border-color 0.2s; } input:focus { border-color: #3b82f6; }
.strength-bar { height: 4px; background: rgba(255,255,255,0.1); border-radius: 2px; margin-top: 8px; } #strength-fill { height: 100%; border-radius: 2px; transition: all 0.3s; width: 0%; }
#strength-label { font-size: 11px; color: #6b7280; margin-top: 4px; display: block; }
.terms { display: flex; align-items: flex-start; gap: 10px; margin-bottom: 20px; } .terms label { font-size: 13px; color: #9ca3af; line-height: 1.5; cursor: pointer; } .terms input { margin-top: 2px; accent-color: #3b82f6; flex-shrink: 0; }
.register-btn { width: 100%; height: 50px; border-radius: 14px; border: none; background: linear-gradient(135deg, #2563eb, #1d4ed8); color: white; font-size: 16px; font-weight: 800; cursor: pointer; transition: opacity 0.2s; } .register-btn:hover { opacity: 0.9; }
#msg { font-size: 13px; text-align: center; margin-top: 12px; min-height: 18px; }

js:
function checkStrength() {
  const pass = document.getElementById('pass').value;
  const fill = document.getElementById('strength-fill');
  const label = document.getElementById('strength-label');
  let strength = 0;
  if (pass.length >= 8) strength++;
  if (/[A-Z]/.test(pass)) strength++;
  if (/[0-9]/.test(pass)) strength++;
  if (/[^A-Za-z0-9]/.test(pass)) strength++;
  const levels = [{w:'25%',c:'#ef4444',t:'Zayıf'},{w:'50%',c:'#f97316',t:'Orta'},{w:'75%',c:'#eab308',t:'İyi'},{w:'100%',c:'#22c55e',t:'Güçlü'}];
  const l = levels[Math.max(0, strength-1)] || {w:'0%',c:'#ef4444',t:'Çok Zayıf'};
  if (pass.length === 0) { fill.style.width='0'; label.textContent='Şifre gücü'; return; }
  fill.style.width = l.w; fill.style.background = l.c; label.textContent = l.t; label.style.color = l.c;
}
function register() {
  const fname = document.getElementById('fname').value.trim();
  const lname = document.getElementById('lname').value.trim();
  const email = document.getElementById('email').value.trim();
  const pass = document.getElementById('pass').value;
  const pass2 = document.getElementById('pass2').value;
  const terms = document.getElementById('terms').checked;
  const msg = document.getElementById('msg');
  if (!fname || !lname || !email || !pass || !pass2) { msg.style.color='#ef4444'; msg.textContent='⚠️ Tüm alanları doldurun.'; return; }
  if (!email.includes('@')) { msg.style.color='#ef4444'; msg.textContent='⚠️ Geçerli e-posta girin.'; return; }
  if (pass.length < 8) { msg.style.color='#ef4444'; msg.textContent='⚠️ Şifre en az 8 karakter olmalı.'; return; }
  if (pass !== pass2) { msg.style.color='#ef4444'; msg.textContent='⚠️ Şifreler eşleşmiyor.'; return; }
  if (!terms) { msg.style.color='#ef4444'; msg.textContent='⚠️ Koşulları kabul etmelisiniz.'; return; }
  msg.style.color='#22c55e'; msg.textContent='✓ Hesabınız oluşturuldu! Hoş geldiniz, '+fname+'!';
  document.querySelector('.register-btn').textContent='✓ Kaydedildi';
  document.querySelector('.register-btn').style.background='#22c55e';
}
